var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`조, 종신계약이요? 이름만 들어도 저 같은 비기너 인생에 어울리는 난이도는 아닌데요...?`,JPN:`しゅ、終身契約ですか……？　よくわからないですけど、
それって……ビギナーのヒミコには難易度が高すぎませんか……？`,ENG:`A-a lifetime contract? The name alone sounds absolutely irrelevant to someone as new and green as me.`,TWN:`終、終身契約嗎？光聽名稱，就感覺這個難易度和我這種菜雞人生不合耶？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`리얼 파이트는 역시 MP적으로 힘들기도 하고요......`,JPN:`MP的にもきついですし、リアルの殴り合いはご遠慮したいんですけど……`,ENG:`I don't know if I've got enough MP to handle real fights, either...`,TWN:`果然在現實戰鬥中，MP果然會有點缺啊……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`......아, 아뇨. 싫다는 뜻은 아닌데요.`,JPN:`……い、いえ…別に嫌というわけじゃ……`,ENG:`Oh no, I'm not saying I don't want it.`,TWN:`……啊，沒有。我沒有說不願意。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`저, 정확히는 싸우기가 힘들다는 거지, 사장님이랑은 계속 함께 있으면 좋겠어요......`,JPN:`リ、リアルで戦うのが大変なだけで、社長とは、ずっと一緒にいたいと思うんです……`,ENG:`I-I'm just saying that I don't like fighting. I'd love to stay with you.`,TWN:`正、正確來說，戰鬥雖然很困難，但如果能和老闆在一起就沒問題了……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`전 스펙도 낮고 컨트롤도 엉망이지만......`,JPN:`ヒミコはスペックだって低いし、操作もヘタッピですけど……`,ENG:`I don't have high stats or good control skills, but...`,TWN:` 我的條件很低，自我管理也很糟，但是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`사장님이랑 지내다 보면...... 사장님처럼 되고 싶다는 생각이 가끔은 든다고 해야 할까...... 그런 느낌적인 느낌이 들어서요......`,JPN:`社長と一緒に過ごしてると……社長のようになりたいような気がしないでもないような……いえ、これはもう確定的に明らかだと思うんですけど……`,ENG:`When I'm with you, I want to be like you sometimes. Kind of.`,TWN:`和老闆在一起……偶爾會想成為像老闆這樣的人……會有這種感覺……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`저, 그러니까......`,JPN:`えっと、ですから……`,ENG:`Erm, so...`,TWN:`我、我……所以說……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`파티 초대...... 부탁드려도 될까요......?`,JPN:`パーティ招待……お願いしてもいいでしょうか……？`,ENG:`May I join your party?`,TWN:`組隊邀請……可以拜託您嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};